import{_ as t,o as r,c as o,a2 as a}from"./chunks/framework.YhErEiPK.js";const s="/stubborn-contract/assets/Deps.Db2wl4x9.png",n="/stubborn-contract/assets/Stubs2.DzI7Caez.png",m=JSON.parse('{"title":"Introduction to Stubborn Contract","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md"}'),i={name:"getting-started/index.md"};function c(l,e,u,d,h,p){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="introduction-to-stubborn-contract" tabindex="-1">Introduction to Stubborn Contract <a class="header-anchor" href="#introduction-to-stubborn-contract" aria-label="Permalink to &quot;Introduction to Stubborn Contract&quot;">​</a></h1><p>Stubborn Contract moves TDD to the level of software architecture. It lets you perform consumer-driven and producer-driven contract testing.</p><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><p>Before Stubborn Contract, this project was called <a href="https://github.com/Codearte/accurest" target="_blank" rel="noreferrer">Accurest</a>. It was created by <a href="https://twitter.com/mgrzejszczak" target="_blank" rel="noreferrer">Marcin Grzejszczak</a> and <a href="https://twitter.com/jkubrynski" target="_blank" rel="noreferrer">Jakub Kubrynski</a>.</p><p>The <code>0.1.0</code> release took place on 26 Jan 2015 and became stable with the <code>1.0.0</code> release on 29 Feb 2016.</p><h2 id="why-do-you-need-it" tabindex="-1">Why Do You Need It? <a class="header-anchor" href="#why-do-you-need-it" aria-label="Permalink to &quot;Why Do You Need It?&quot;">​</a></h2><p>Assume you have a system composed of multiple microservices:</p><p><img src="'+s+'" alt="Microservices Architecture"></p><h3 id="testing-issues" tabindex="-1">Testing Issues <a class="header-anchor" href="#testing-issues" aria-label="Permalink to &quot;Testing Issues&quot;">​</a></h3><p>If you want to test your application in full, you can either:</p><ul><li>Deploy all microservices and perform end-to-end tests.</li><li>Mock other microservices in unit and integration tests.</li></ul><p>Both approaches have their advantages and disadvantages.</p><p><strong>Deploy all microservices and perform end-to-end tests</strong></p><p>Advantages:</p><ul><li>Simulates production.</li><li>Tests real communication between services.</li></ul><p>Disadvantages:</p><ul><li>To test one microservice, you must deploy all dependent microservices, databases, etc.</li><li>The test run is locked for a single suite.</li><li>You can go to production with passing tests but failing production behavior.</li></ul><p><strong>Mock other microservices</strong></p><p>Advantages:</p><ul><li>Very fast feedback.</li><li>No infrastructure dependencies for the CI/CD pipeline.</li></ul><p>Disadvantages:</p><ul><li>The implementor of the stub may make it behave differently from the real service, giving false-positive test results.</li></ul><p>That is why Stubborn Contract was created: to give you very fast feedback without needing to set up an entire microservice world. You work on stubs, and only the applications that your application directly uses need to be running.</p><p><img src="'+n+'" alt="Stubbed Services"></p><p>Stubborn Contract ensures that the stubs you use were created by the service you call and that they were tested against the producer&#39;s side. You can trust those stubs.</p><h2 id="what-does-stubborn-contract-provide" tabindex="-1">What Does Stubborn Contract Provide? <a class="header-anchor" href="#what-does-stubborn-contract-provide" aria-label="Permalink to &quot;What Does Stubborn Contract Provide?&quot;">​</a></h2><p>The main features of Stubborn Contract are:</p><ul><li>Ensure that HTTP and messaging stubs (used when developing the consumer side) do exactly what the actual server-side implementation does.</li><li>Promote ATDD (Acceptance Test-Driven Development) and microservices architectural style.</li><li>Provide a way to publish changes in contracts that are visible immediately on both sides.</li><li>Generate boilerplate test code on the server side.</li></ul><p>Stubborn Contract integrates with <a href="http://wiremock.org" target="_blank" rel="noreferrer">WireMock</a> as the HTTP server stub.</p><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>Contracts must come from a <strong>trusted source</strong>. You should never download nor interact with contracts coming from untrusted locations.</p></div><h2 id="the-purpose-of-contracts" tabindex="-1">The Purpose of Contracts <a class="header-anchor" href="#the-purpose-of-contracts" aria-label="Permalink to &quot;The Purpose of Contracts&quot;">​</a></h2><p>Stubborn Contract&#39;s purpose is NOT to start writing business features in contracts. Suppose a user can be flagged as a fraud for two reasons. You then have two contracts, one for the positive case and one for the negative case.</p><p>A contract is an agreement on what the API provides. Given the fraud detection example:</p><ul><li>A consumer sends a request containing the ID of a client company and the amount they want to borrow to the <code>/fraudcheck</code> URL using the <code>PUT</code> method.</li></ul><p><a href="https://github.com/stubborn-sh/stubborn-samples/tree/main/standalone/dsl/http-server/src/test/resources/contracts/fraud/shouldMarkClientAsFraud.groovy" target="_blank" rel="noreferrer">Click here to see a Groovy contract example</a></p><p><a href="https://github.com/stubborn-sh/stubborn-samples/tree/main/standalone/dsl/http-server/src/test/resources/contracts/yml/fraud/shouldMarkClientAsFraud.yml" target="_blank" rel="noreferrer">Click here to see a YAML contract example</a></p>',36)])])}const f=t(i,[["render",c]]);export{m as __pageData,f as default};
